import{_ as a,o as r,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"Tracking Progress","description":"","frontmatter":{},"headers":[],"relativePath":"training/tracking-progress.md","filePath":"training/tracking-progress.md"}'),i={name:"training/tracking-progress.md"};function s(o,e,c,l,h,g){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="tracking-progress" tabindex="-1">Tracking Progress <a class="header-anchor" href="#tracking-progress" aria-label="Permalink to &quot;Tracking Progress&quot;">​</a></h1><p>Training plans are live — they update as new game and practice data is logged. This lets you see whether a plan is working without manually checking the analytics.</p><h2 id="progress-indicators" tabindex="-1">Progress Indicators <a class="header-anchor" href="#progress-indicators" aria-label="Permalink to &quot;Progress Indicators&quot;">​</a></h2><p>Each active training plan shows a progress indicator based on the target metric:</p><ul><li><strong>Improving</strong> — the metric is trending toward the target</li><li><strong>Stable</strong> — the metric has not changed significantly since the plan was created</li><li><strong>Declining</strong> — the metric is moving further from the target</li></ul><p>Progress is calculated by comparing the metric at plan creation vs the current rolling average.</p><h2 id="viewing-progress-charts" tabindex="-1">Viewing Progress Charts <a class="header-anchor" href="#viewing-progress-charts" aria-label="Permalink to &quot;Viewing Progress Charts&quot;">​</a></h2><p>Tap any active training plan to open the detail view. The detail view shows:</p><ul><li>The metric trend chart since the plan was created</li><li>The target value marked on the chart</li><li>Recent session data points</li></ul><h2 id="when-to-archive-a-plan" tabindex="-1">When to Archive a Plan <a class="header-anchor" href="#when-to-archive-a-plan" aria-label="Permalink to &quot;When to Archive a Plan&quot;">​</a></h2><p>Archive a training plan when:</p><ul><li>The metric has improved past the target and held there for at least two weeks</li><li>You have changed your approach and created a new plan</li><li>The season is over and you want a clean active plan view for next season</li></ul><p>Archived plans remain in the player&#39;s history and can be referenced when writing report card comments.</p><h2 id="connecting-plans-to-report-cards" tabindex="-1">Connecting Plans to Report Cards <a class="header-anchor" href="#connecting-plans-to-report-cards" aria-label="Permalink to &quot;Connecting Plans to Report Cards&quot;">​</a></h2><p>Active and recently archived training plans appear in the Training section of player report cards. This shows families what specific areas are being developed and how progress is tracking. See <a href="/report-cards/">Player Report Cards</a> for details.</p>',15)])])}const m=a(i,[["render",s]]);export{d as __pageData,m as default};
